export type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
  (x1 !== x2 || y1 !== y2) &&
  Math.abs(x1 - x2) <= 1 &&
  Math.abs(y1 - y2) <= 1;

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => isNeighbor(cell, other)).length;

export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) => countNeighbors(cell, cells) >= 2);
  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        candidates.push([x + dx, y + dy]);
      }
    }
  }
  const isLive = (cell: Cell): boolean =>
    cells.some(([x, y]) => x === cell[0] && y === cell[1]);
  const births: Cell[] = [];
  for (const cand of candidates) {
    if (isLive(cand)) continue;
    if (births.some(([x, y]) => x === cand[0] && y === cand[1])) continue;
    if (countNeighbors(cand, cells) === 3) births.push(cand);
  }
  return [...survivors, ...births];
}

